SELECT SUM(games_played) AS total_games, SUM(wins) AS total_wins
FROM season_records
WHERE team_id = 0;

SELECT MAX(followers) AS max_followers
FROM social_media
WHERE platform = 'Twitter';

SELECT team_name
FROM teams
ORDER BY team_name ASC;

SELECT MAX(total_points) AS highest_total_points
FROM (
  SELECT SUM(points) AS total_points
  FROM player_stats
  GROUP BY player_id
);
